from __future__ import annotations

import argparse
import re
import sys
from pathlib import Path

import yaml
from gi.repository import GLib, Gio

# is_available() and SecretService live in kwin_lib so they can also be called
# from kwin_restore.py.  We import them here to expose them via the 'check'
# and 'check-ready' subcommands for bash callers.
import os as _os
sys.path.insert(0, _os.path.dirname(_os.path.abspath(__file__)))
from kwin_lib.secret_service import is_available as _ss_is_available
from kwin_lib.secret_service import SecretService as _SecretService
from kwin_lib.config         import load_config


# ── D-Bus constants ───────────────────────────────────────────────────────────

SS_BUS      = "org.freedesktop.secrets"
SS_PATH     = "/org/freedesktop/secrets"
SS_SERVICE  = "org.freedesktop.Secret.Service"
SS_COLL     = "org.freedesktop.Secret.Collection"
SS_ITEM     = "org.freedesktop.Secret.Item"
SS_SESSION  = "org.freedesktop.Secret.Session"
SS_PROMPT   = "org.freedesktop.Secret.Prompt"

DEFAULT_COLLECTION = "/org/freedesktop/secrets/aliases/default"


# ── Proxy helpers ─────────────────────────────────────────────────────────────

def _make_proxy(iface: str, path: str) -> Gio.DBusProxy:
    return Gio.DBusProxy.new_for_bus_sync(
        Gio.BusType.SESSION,
        Gio.DBusProxyFlags.NONE,
        None,
        SS_BUS, path, iface,
        None,
    )


def _call(proxy: Gio.DBusProxy, method: str, args: GLib.Variant) -> GLib.Variant:
    return proxy.call_sync(method, args, Gio.DBusCallFlags.NONE, -1, None)


def _get_prop(proxy: Gio.DBusProxy, prop: str):
    cached = proxy.get_cached_property(prop)
    if cached is not None:
        return cached.unpack()
    result = proxy.call_sync(
        "org.freedesktop.DBus.Properties.Get",
        GLib.Variant("(ss)", (proxy.get_interface_name(), prop)),
        Gio.DBusCallFlags.NONE, -1, None,
    )
    return result[0]


def _prompt_if_needed(prompt_path: str) -> None:
    if prompt_path == "/":
        return
    loop   = GLib.MainLoop()
    result = [None]
    conn   = Gio.bus_get_sync(Gio.BusType.SESSION, None)

    def on_completed(conn2, sender, obj_path, iface, signal, params, user_data):
        dismissed, _res = params
        result[0] = dismissed
        loop.quit()

    sub_id = conn.signal_subscribe(
        SS_BUS, SS_PROMPT, "Completed",
        prompt_path, None,
        Gio.DBusSignalFlags.NONE,
        on_completed, None,
    )
    prompt_proxy = _make_proxy(SS_PROMPT, prompt_path)
    _call(prompt_proxy, "Prompt", GLib.Variant("(s)", ("",)))
    GLib.timeout_add_seconds(60, loop.quit)
    loop.run()
    conn.signal_unsubscribe(sub_id)
    if result[0]:
        raise RuntimeError("Unlock prompt was dismissed.")


def _open_session() -> tuple[Gio.DBusProxy, str]:
    svc    = _make_proxy(SS_SERVICE, SS_PATH)
    result = _call(svc, "OpenSession",
                   GLib.Variant("(sv)", ("plain", GLib.Variant("s", ""))))
    return svc, result[1]


def _unlock_collection(svc: Gio.DBusProxy, collection_path: str) -> None:
    coll   = _make_proxy(SS_COLL, collection_path)
    locked = _get_prop(coll, "Locked")
    if not locked:
        return
    result      = _call(svc, "Unlock", GLib.Variant("(ao)", ([collection_path],)))
    prompt_path = result[1]
    _prompt_if_needed(prompt_path)
    coll2 = _make_proxy(SS_COLL, collection_path)
    if _get_prop(coll2, "Locked"):
        raise RuntimeError(
            "Collection is still locked after unlock attempt. "
            "KeePassXC may be closed or the unlock was cancelled."
        )


def _list_item_paths(collection_path: str) -> list[str]:
    return list(_get_prop(_make_proxy(SS_COLL, collection_path), "Items"))


def _item_label(item_path: str) -> str:
    return str(_get_prop(_make_proxy(SS_ITEM, item_path), "Label"))


def _item_attributes(item_path: str) -> dict[str, str]:
    raw = _get_prop(_make_proxy(SS_ITEM, item_path), "Attributes")
    return dict(raw) if raw else {}


def _item_secret(item_path: str, session_path: str, svc: Gio.DBusProxy) -> str:
    item = _make_proxy(SS_ITEM, item_path)
    try:
        result = _call(item, "GetSecret", GLib.Variant("(o)", (session_path,)))
    except Exception as exc:
        if "IsLocked" not in str(exc):
            raise
        # Per-item unlock required (KeePassXC approval dialog)
        unlock_result = _call(svc, "Unlock", GLib.Variant("(ao)", ([item_path],)))
        _prompt_if_needed(unlock_result[1])
        item   = _make_proxy(SS_ITEM, item_path)
        result = _call(item, "GetSecret", GLib.Variant("(o)", (session_path,)))
    return bytes(result[0][2]).decode("utf-8")


def _close_session(session_path: str) -> None:
    try:
        _call(_make_proxy(SS_SESSION, session_path), "Close", GLib.Variant("()", ()))
    except Exception:
        pass


# ── Setup-file resolution and PASS-token extraction ───────────────────────────

# Matches {PASS key} tokens in input_actions DSL, case-insensitive.
# The key is everything after "PASS " up to the closing brace, stripped.
_PASS_RE = re.compile(r"\{PASS\s+([^}]+)\}", re.IGNORECASE)


def _resolve_setup_file(setup_arg: str | None, cfg) -> Path | None:
    """
    Reproduce the setup-file search order used by kwin_restore.py.

    Priority:
      1. setup_arg (explicit --setup path, ~ expanded)
      2. cfg.default_setup filename, searched in:
           current dir → ~/.config/wayland-desktop/ → cfg.snapshot_dir
    Returns None if the file cannot be found.
    """
    if setup_arg:
        p = Path(setup_arg).expanduser()
        return p if p.exists() else None

    if not cfg.default_setup:
        return None

    filename   = cfg.default_setup
    config_dir = Path("~/.config/wayland-desktop").expanduser()
    for candidate in [
        Path(filename),
        config_dir / filename,
        cfg.snapshot_dir / filename,
    ]:
        resolved = candidate.expanduser().resolve()
        if resolved.exists():
            return resolved

    return None


def _collect_pass_keys(setup_path: Path) -> list[str]:
    """
    Load the setup YAML and collect every unique {PASS key} token found in
    any input_actions field, preserving the order of first appearance.
    Returns an empty list if no PASS tokens are present.
    """
    try:
        with setup_path.open(encoding="utf-8") as fh:
            data = yaml.safe_load(fh)
    except Exception as exc:
        print(f"Secret Service check-ready: cannot load setup file: {exc}",
              file=sys.stderr)
        return []

    seen: set[str]   = set()
    keys: list[str]  = []

    entries = []
    if isinstance(data, dict):
        entries = data.get("entries", []) or []
    if isinstance(data, list):
        entries = data

    for entry in entries:
        if not isinstance(entry, dict):
            continue
        dsl = (entry.get("input_actions") or "").strip()
        if not dsl:
            continue
        for m in _PASS_RE.finditer(dsl):
            key = m.group(1).strip()
            if key and key not in seen:
                seen.add(key)
                keys.append(key)

    return keys


# ── Commands ──────────────────────────────────────────────────────────────────

def cmd_check_ready(args) -> int:
    """
    Full Secret Service readiness check for the 'restore' bash wrapper.

    Loads the setup YAML, collects every unique {PASS key} token from
    input_actions fields, then attempts get_password() for each key.
    Prints a per-key pass/fail line to stderr so the user can see which
    entries are blocked or missing.  Exits 0 only if ALL keys succeeded.

    Falls back to the basic is_available() probe when the setup file
    cannot be found or contains no PASS tokens.
    """
    cfg = load_config(getattr(args, "config", None) or None)

    setup_arg  = getattr(args, "setup", None) or None
    setup_path = _resolve_setup_file(setup_arg, cfg)

    if setup_path is None:
        # Cannot find the setup file — fall back to the lightweight probe.
        print("Secret Service check-ready: setup file not found, "
              "falling back to basic availability check", file=sys.stderr)
        if _ss_is_available():
            print("Secret Service: available (no PASS tokens verified)",
                  file=sys.stderr)
            return 0
        else:
            print("Secret Service: not available", file=sys.stderr)
            return 1

    pass_keys = _collect_pass_keys(setup_path)

    if not pass_keys:
        # No PASS tokens in snapshot — basic probe is sufficient.
        if _ss_is_available():
            print("Secret Service: available (no PASS tokens in snapshot)",
                  file=sys.stderr)
            return 0
        else:
            print("Secret Service: not available", file=sys.stderr)
            return 1

    # Attempt to fetch every PASS key and report per-key results.
    print(f"Secret Service check-ready: testing {len(pass_keys)} PASS "
          f"token(s) from {setup_path.name}", file=sys.stderr)

    ss = _SecretService()
    try:
        ss.open()
    except RuntimeError as exc:
        print(f"Secret Service: cannot open session — {exc}", file=sys.stderr)
        return 1

    all_ok = True
    try:
        for key in pass_keys:
            try:
                ss.get_password(key)
                print(f"  [OK    ] {key!r}", file=sys.stderr)
            except Exception as exc:
                # Strip trailing newlines from the exception message so the
                # per-key line stays on one line for easy reading.
                reason = str(exc).splitlines()[0]
                print(f"  [FAILED] {key!r} — {reason}", file=sys.stderr)
                all_ok = False
    finally:
        ss.close()

    if all_ok:
        print("Secret Service: all PASS tokens verified OK", file=sys.stderr)
        return 0
    else:
        print("Secret Service: one or more PASS tokens could not be fetched",
              file=sys.stderr)
        return 1


def cmd_check(args) -> int:
    """
    Test whether the Secret Service is reachable.

    Calls is_available() from kwin_lib.secret_service, which opens a plain
    session and immediately closes it.  Exits 0 if the service responded, 1
    if not.  The one-line result is written to stderr so it does not pollute
    stdout when this command is used inside shell $() capture.

    This is the entry point used by the 'restore' bash wrapper to decide
    whether to loop Dialog #2 or proceed.
    """
    if _ss_is_available():
        print("Secret Service: available", file=sys.stderr)
        return 0
    else:
        print("Secret Service: not available", file=sys.stderr)
        return 1


def cmd_list(args) -> int:
    """List all items in the collection with their labels."""
    collection_path = args.collection
    try:
        svc, session_path = _open_session()
    except Exception as exc:
        print(f"ERROR opening session: {exc}", file=sys.stderr)
        return 1
    try:
        _unlock_collection(svc, collection_path)
    except Exception as exc:
        print(f"ERROR unlocking collection: {exc}", file=sys.stderr)
        return 1
    try:
        item_paths = _list_item_paths(collection_path)
    except Exception as exc:
        print(f"ERROR listing items: {exc}", file=sys.stderr)
        return 1

    items = []
    for path in item_paths:
        try:
            label = _item_label(path)
            attrs = _item_attributes(path)
            items.append((label, attrs, path))
        except Exception as exc:
            items.append((f"(unreadable: {exc})", {}, path))
    items.sort(key=lambda t: t[0].lower())

    for label, attrs, path in items:
        if args.verbose:
            print(f"  Label   : {label}")
            print(f"  Path    : {path}")
            for k, v in sorted(attrs.items()):
                print(f"  {k:<12}: {v}")
            print()
        else:
            username = attrs.get("UserName", attrs.get("username", ""))
            user_part = f"  (UserName: {username})" if username else ""
            print(f"  {label}{user_part}")

    _close_session(session_path)
    return 0


def cmd_lookup(args) -> int:
    """Look up a secret by label and print it to stdout."""
    key             = args.key
    collection_path = args.collection
    try:
        svc, session_path = _open_session()
    except Exception as exc:
        print(f"ERROR opening session: {exc}", file=sys.stderr)
        return 1
    try:
        _unlock_collection(svc, collection_path)
        item_paths = _list_item_paths(collection_path)
    except Exception as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        _close_session(session_path)
        return 1

    found_path = None
    for path in item_paths:
        try:
            if _item_label(path) == key:
                found_path = path
                break
        except Exception:
            continue

    if found_path is None:
        print(f"ERROR: No item found with label {key!r}.", file=sys.stderr)
        print("Use 'list' to see all available labels.", file=sys.stderr)
        _close_session(session_path)
        return 1

    try:
        secret = _item_secret(found_path, session_path, svc)
    except Exception as exc:
        print(f"ERROR retrieving secret: {exc}", file=sys.stderr)
        _close_session(session_path)
        return 1

    # Print secret with no trailing newline so callers can capture it cleanly
    # via: SECRET=$(secret-service lookup "key")
    print(secret, end="")
    _close_session(session_path)
    return 0


# ── Main ──────────────────────────────────────────────────────────────────────

def main() -> None:
    parser = argparse.ArgumentParser(
        prog="kwin_secret_service.py",
        description="List and look up secrets from the org.freedesktop.secrets Secret Service.",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog=(
            "Commands:\n"
            "  check               Exit 0 if Secret Service is reachable, 1 if not\n"
            "  check-ready         Fetch every {PASS key} from snapshot; exit 0 if all OK\n"
            "  list                List all item labels (and UserName attributes)\n"
            "  lookup <key>        Print the secret for the item with label <key>\n"
            "\n"
            "Note: lookup prints the secret with no trailing newline, suitable\n"
            "for shell capture:  SECRET=$(secret-service lookup \"my-key\")\n"
        ),
    )
    parser.add_argument(
        "--collection", default=DEFAULT_COLLECTION, metavar="PATH",
        help=f"Collection D-Bus path (default: {DEFAULT_COLLECTION})",
    )
    sub = parser.add_subparsers(dest="command")

    sub.add_parser("check", help="Test Secret Service availability (exit 0=ok, 1=unavailable)")

    p_check_ready = sub.add_parser(
        "check-ready",
        help="Fetch every {PASS key} from snapshot; exit 0 only if all succeed",
    )
    p_check_ready.add_argument(
        "--setup", default="", metavar="FILE",
        help="Snapshot file to inspect (default: read default_setup from config.yaml)",
    )
    p_check_ready.add_argument(
        "--config", default="", metavar="FILE",
        help="Alternate config file",
    )

    p_list = sub.add_parser("list", help="List all items")
    p_list.add_argument("--verbose", action="store_true",
                        help="Show all attributes for each item")

    p_lookup = sub.add_parser("lookup", help="Look up a secret by label")
    p_lookup.add_argument("key", help="Entry label (title) to look up")

    args = parser.parse_args()
    if args.command is None:
        parser.print_help()
        sys.exit(0)

    sys.exit({
        "check":       cmd_check,
        "check-ready": cmd_check_ready,
        "list":        cmd_list,
        "lookup":      cmd_lookup,
    }[args.command](args))


if __name__ == "__main__":
    main()
